package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testFormat_withNormalValues() throws IOException {
        try (MockedConstruction<CSVPrinter> mocked = mockConstruction(CSVPrinter.class,
                (mock, context) -> {
                    doNothing().when(mock).printRecord("a", "b", "c");
                })) {
            String result = csvFormat.format("a", "b", "c");
            assertNotNull(result);
            // Because CSVPrinter is mocked, it returns empty string trimmed
            assertEquals("", result);
            // Verify CSVPrinter constructor called with StringWriter and csvFormat
            assertEquals(1, mocked.constructed().size());
            CSVPrinter printer = mocked.constructed().get(0);
            verify(printer).printRecord("a", "b", "c");
        }
    }

    @Test
    public void testFormat_withNullValues() throws IOException {
        try (MockedConstruction<CSVPrinter> mocked = mockConstruction(CSVPrinter.class,
                (mock, context) -> {
                    doNothing().when(mock).printRecord((Object) null);
                })) {
            String result = csvFormat.format((Object) null);
            assertNotNull(result);
            assertEquals("", result);
            assertEquals(1, mocked.constructed().size());
            CSVPrinter printer = mocked.constructed().get(0);
            verify(printer).printRecord((Object) null);
        }
    }

    @Test
    public void testFormat_withEmptyValues() throws IOException {
        try (MockedConstruction<CSVPrinter> mocked = mockConstruction(CSVPrinter.class,
                (mock, context) -> {
                    doNothing().when(mock).printRecord();
                })) {
            String result = csvFormat.format();
            assertNotNull(result);
            assertEquals("", result);
            assertEquals(1, mocked.constructed().size());
            CSVPrinter printer = mocked.constructed().get(0);
            verify(printer).printRecord();
        }
    }

    @Test
    public void testFormat_throwsIOException() throws IOException {
        try (MockedConstruction<CSVPrinter> mocked = mockConstruction(CSVPrinter.class,
                (mock, context) -> {
                    doThrow(new IOException("IO error")).when(mock).printRecord(any());
                })) {
            IllegalStateException ex = assertThrows(IllegalStateException.class, () -> {
                csvFormat.format("a");
            });
            assertTrue(ex.getCause() instanceof IOException);
            assertEquals("IO error", ex.getCause().getMessage());
            assertEquals(1, mocked.constructed().size());
            CSVPrinter printer = mocked.constructed().get(0);
            verify(printer).printRecord("a");
        }
    }
}
